def range_summary(nums):
    if not nums:
        return ''

    sorted_nums = sorted(set(nums))
    result = []
    i, n = 0, len(sorted_nums)

    while i < n:
        start = sorted_nums[i]
        while i + 1 < n and sorted_nums[i + 1] == sorted_nums[i] + 1:
            i += 1
        end = sorted_nums[i]
        if start == end:
            result.append(str(start))
        else:
            result.append(f'{start}-{end}')
        i += 1

    return ','.join(result)
